import datetime

from django.http import HttpResponse
from django.test import SimpleTestCase


class CookieTests(SimpleTestCase):
    def test_httponly_cookie(self):
        response = HttpResponse()
        response.set_cookie('test', 'value', httponly=True)
        self.assertIn('; httponly', str(response.cookies['test']))

    def test_limited_as_json(self):
        """
        Cookies with characters that don't belong in a JSON document should
        be properly quoted (#22259).
        """
        response = HttpResponse()
        response.set_cookie('test', 'new\nline')
        self.assertEqual(str(response.cookies['test']), 'Set-Cookie: test="new\\012line"; Path=/')

    def test_unicode_cookie(self):
        """Unicode strings are stored as bytes in SimpleCookie."""
        response = HttpResponse()
        response.set_cookie('test', 'café')
        morsel = response.cookies['test']
        self.assertEqual(morsel.value, 'café')
        self.assertEqual(morsel.output(), 'Set-Cookie: test=café; Path=/')

    def test_samesite_cookie(self):
        response = HttpResponse()
        response.set_cookie('test', 'value', samesite='strict')
        self.assertIn('; samesite=strict', str(response.cookies['test']))

    def test_invalid_samesite_cookie(self):
        response = HttpResponse()
        msg = 'samesite must be "lax", "none", or "strict".'
        with self.assertRaisesMessage(ValueError, msg):
            response.set_cookie('test', 'value', samesite='invalid')

    def test_delete_cookie(self):
        response = HttpResponse()
        response.set_cookie('test', 'value')
        response.delete_cookie('test')
        cookie = response.cookies['test']
        self.assertEqual(cookie['expires'], 'Thu, 01 Jan 1970 00:00:00 GMT')
        self.assertEqual(cookie['max-age'], 0)
        self.assertEqual(cookie['path'], '/')
        self.assertEqual(cookie['secure'], '')

    def test_delete_cookie_secure_prefix(self):
        """
        delete_cookie() sets the secure flag if the cookie name starts with
        __Secure- or __Host-.
        """
        response = HttpResponse()
        for prefix in ('__Secure-', '__Host-'):
            with self.subTest(prefix=prefix):
                cookie_name = prefix + 'test'
                response.set_cookie(cookie_name, 'value')
                response.delete_cookie(cookie_name)
                cookie = response.cookies[cookie_name]
                self.assertEqual(cookie['expires'], 'Thu, 01 Jan 1970 00:00:00 GMT')
                self.assertEqual(cookie['max-age'], 0)
                self.assertEqual(cookie['path'], '/')
                self.assertIs(cookie['secure'], True)

    def test_cookie_edgecases(self):
        # Ensure we can use unicode in cookie values
        response = HttpResponse()
        response.set_cookie('unicode_value', 'Iñtërnâtiônàlizætiøn1')
        self.assertEqual(response.cookies['unicode_value'].value, 'Iñtërnâtiônàlizætiøn1')

