class MessageEncoder(json.JSONEncoder):
    """
    Compacts JSON by removing whitespace after separators.
    """
    def __init__(self, *args, **kwargs):
        kwargs.setdefault('separators', (',', ':'))
        super().__init__(*args, **kwargs)

    def default(self, obj):
        if isinstance(obj, Message):
            # Using the message.level_tag property forces the message to
            # render with the MESSAGE_TAGS setting instead of whatever tag
            # was passed to the method that generated the message.
            message = [None, obj.level, obj.message]
            if obj.extra_tags:
